      <h2 className="gold-text" style={{ textAlign: 'center', marginBottom: '25px' }}>Uploaded ZIP Catalog ({zipImages.length} Items)</h2>
      {isLoading ? (
        <p style={{ color: '#d4af37', textAlign: 'center' }}>Loading zip contents...</p>
      ) : zipImages.length > 0 ? (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '20px' }}>
          {zipImages.map((img, idx) => (
            <div key={idx} className="animated-card" style={{ background: '#141414', border: '1px solid #d4af37', borderRadius: '8px', padding: '10px' }}>
              <img src={img.url} alt={img.name} style={{ width: '100%', height: '220px', objectFit: 'cover', borderRadius: '6px' }} />
            </div>
          ))}
        </div>
      ) : (
        <p style={{ color: '#888', textAlign: 'center' }}>Place <code>catalog.zip</code> in <code>client/public/</code> to render images here.</p>
      )}
    </section>

    {/* Section 2: Online Image Showcase */}
    <section style={{ marginBottom: '60px' }}>
      <h2 className="gold-text" style={{ textAlign: 'center', marginBottom: '25px' }}>Design Inspirations</h2>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '20px' }}>
        <img className="animated-card" src={IMAGES.curtainDrapes} alt="Curtains 1" style={{ width: '100%', height: '250px', objectFit: 'cover', borderRadius: '8px' }} />
        <img className="animated-card" src={IMAGES.mosquitoNet} alt="Mosquito Net 2" style={{ width: '100%', height: '250px', objectFit: 'cover', borderRadius: '8px' }} />
        <img className="animated-card" src={IMAGES.sheerCurtains} alt="Sheer 3" style={{ width: '100%', height: '250px', objectFit: 'cover', borderRadius: '8px' }} />
      </div>
    </section>
  </div>
);

/* ==========================================================================
   5. CONTACT PAGE
   ========================================================================== */
const ContactPage = () => (
  <div style={{ maxWidth: '1000px', margin: '0 auto', padding: '40px 20px' }}>
    <section style={{ textAlign: 'center', marginBottom: '40px' }}>
      <h1 className="gold-text animated-heading" style={{ fontSize: '2.8rem', marginBottom: '10px' }}>Contact Us</h1>
      <p style={{ color: '#aaa' }}>Book a doorstep visit for curtain and mosquito net measurements.</p>
    </section>

    <section style={{ background: '#141414', border: '1px solid #333', padding: '40px', borderRadius: '10px', marginBottom: '50px' }}>
      <h2 className="gold-text" style={{ marginBottom: '20px' }}>Book Appointment</h2>
      <form style={{ display: 'grid', gap: '15px' }}>
        <input type="text" placeholder="Full Name" style={{ padding: '12px', background: '#0a0a0a', border: '1px solid #333', color: '#fff', borderRadius: '4px' }} />
        <input type="email" placeholder="Email Address" style={{ padding: '12px', background: '#0a0a0a', border: '1px solid #333', color: '#fff', borderRadius: '4px' }} />
        <input type="tel" placeholder="Phone Number" style={{ padding: '12px', background: '#0a0a0a', border: '1px solid #333', color: '#fff', borderRadius: '4px' }} />
        <textarea placeholder="Tell us about your window curtain or mosquito net requirements..." rows="4" style={{ padding: '12px', background: '#0a0a0a', border: '1px solid #333', color: '#fff', borderRadius: '4px' }}></textarea>
        <button type="button" className="btn-gold" style={{ padding: '12px', cursor: 'pointer' }}>Submit Request</button>
      </form>
    </section>
  </div>
);

export default App;
